package com.example.biometriclogin

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.text.Editable
import android.text.InputType
import android.text.TextWatcher
import android.view.KeyEvent
import android.view.View
import android.view.inputmethod.EditorInfo
import android.widget.Button
import android.widget.EditText
import android.widget.ProgressBar
import android.widget.TextView
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat

object AuthPrefs {
    private const val PREFS = "auth_prefs"
    private const val KEY_AUTHENTICATED = "authenticated"

    fun prefs(ctx: Context): SharedPreferences = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)

    fun isAuthenticated(ctx: Context): Boolean = prefs(ctx).getBoolean(KEY_AUTHENTICATED, false)

    fun setAuthenticated(ctx: Context, value: Boolean) {
        prefs(ctx).edit().putBoolean(KEY_AUTHENTICATED, value).apply()
    }

    fun clear(ctx: Context) = setAuthenticated(ctx, false)
}

class LoginActivity : AppCompatActivity() {

    private lateinit var btnBiometric: Button
    private lateinit var btnLogin: Button
    private lateinit var etUsername: EditText
    private lateinit var etPassword: EditText
    private lateinit var tvHint: TextView
    private lateinit var progress: ProgressBar

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (AuthPrefs.isAuthenticated(this)) {
            goHome()
            return
        }

        setContentView(R.layout.activity_login)

        btnBiometric = findViewById(R.id.btnBiometric)
        btnLogin = findViewById(R.id.btnLogin)
        etUsername = findViewById(R.id.etUsername)
        etPassword = findViewById(R.id.etPassword)
        tvHint = findViewById(R.id.tvHint)
        progress = findViewById(R.id.progress)

        progress.visibility = View.GONE
        tvHint.text = ""

        setupBiometric()
        setupPasswordFallback()
        setupUserFriendlyShortcuts()

        maybeAutoPromptBiometric()
    }

    private fun setupBiometric() {
        val executor = ContextCompat.getMainExecutor(this)
        biometricPrompt = BiometricPrompt(this, executor, object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                setAuthenticatedAndProceed()
            }

            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                tvHint.text = errString
                showPasswordFallbackUI(focusPassword = true)
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                tvHint.text = getString(R.string.biometric_try_again_or_use_password)
                showPasswordFallbackUI(focusPassword = true)
            }
        })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle(getString(R.string.biometric_title))
            .setSubtitle(getString(R.string.biometric_subtitle))
            .setDescription(getString(R.string.biometric_description))
            .setNegativeButtonText(getString(R.string.use_password))
            .build()

        val canAuth = BiometricManager.from(this)
            .canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)

        val biometricsAvailable = canAuth == BiometricManager.BIOMETRIC_SUCCESS

        btnBiometric.isEnabled = biometricsAvailable
        btnBiometric.visibility = if (biometricsAvailable) View.VISIBLE else View.GONE

        if (!biometricsAvailable) {
            showPasswordFallbackUI(focusPassword = false)
            tvHint.text = when (canAuth) {
                BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> getString(R.string.biometric_no_hardware)
                BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> getString(R.string.biometric_hw_unavailable)
                BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> getString(R.string.biometric_not_enrolled)
                else -> getString(R.string.biometric_unavailable)
            }
        }

        btnBiometric.setOnClickListener {
            tvHint.text = ""
            biometricPrompt.authenticate(promptInfo)
        }
    }

    private fun maybeAutoPromptBiometric() {
        if (btnBiometric.visibility != View.VISIBLE) return

        val autoPrompt = intent.getBooleanExtra(EXTRA_AUTO_PROMPT_BIOMETRIC, true)
        if (autoPrompt) {
            btnBiometric.postDelayed({
                if (!isFinishing && !isDestroyed && !AuthPrefs.isAuthenticated(this)) {
                    tvHint.text = ""
                    biometricPrompt.authenticate(promptInfo)
                }
            }, 250L)
        }
    }

    private fun setupPasswordFallback() {
        showPasswordFallbackUI(focusPassword = false)

        btnLogin.setOnClickListener {
            attemptPasswordLogin()
        }
    }

    private fun setupUserFriendlyShortcuts() {
        etPassword.inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD
        etPassword.setOnEditorActionListener { _, actionId, event ->
            val imeDone = actionId == EditorInfo.IME_ACTION_DONE || actionId == EditorInfo.IME_ACTION_GO
            val enter = event?.keyCode == KeyEvent.KEYCODE_ENTER && event.action == KeyEvent.ACTION_UP
            if (imeDone || enter) {
                attemptPasswordLogin()
                true
            } else {
                false
            }
        }

        val watcher = object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                tvHint.text = ""
            }
            override fun afterTextChanged(s: Editable?) {}
        }
        etUsername.addTextChangedListener(watcher)
        etPassword.addTextChangedListener(watcher)
    }

    private fun showPasswordFallbackUI(focusPassword: Boolean) {
        etUsername.visibility = View.VISIBLE
        etPassword.visibility = View.VISIBLE
        btnLogin.visibility = View.VISIBLE

        if (focusPassword) {
            etPassword.requestFocus()
        }
    }

    private fun attemptPasswordLogin() {
        val user = etUsername.text?.toString()?.trim().orEmpty()
        val pass = etPassword.text?.toString().orEmpty()

        if (user.isEmpty()) {
            etUsername.error = getString(R.string.username_required)
            etUsername.requestFocus()
            return
        }
        if (pass.isEmpty()) {
            etPassword.error = getString(R.string.password_required)
            etPassword.requestFocus()
            return
        }

        progress.visibility = View.VISIBLE
        btnLogin.isEnabled = false
        btnBiometric.isEnabled = false

        etUsername.postDelayed({
            progress.visibility = View.GONE
            btnLogin.isEnabled = true
            btnBiometric.isEnabled = btnBiometric.visibility == View.VISIBLE

            val ok = FakeAuthService.validate(user, pass)
            if (ok) {
                setAuthenticatedAndProceed()
            } else {
                tvHint.text = getString(R.string.invalid_credentials)
                showPasswordFallbackUI(focusPassword = true)
            }
        }, 350L)
    }

    private fun setAuthenticatedAndProceed() {
        AuthPrefs.setAuthenticated(this, true)
        goHome()
    }

    private fun goHome() {
        startActivity(Intent(this, HomeActivity::class.java).apply {
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK)
        })
        finish()
    }

    companion object {
        const val EXTRA_AUTO_PROMPT_BIOMETRIC = "extra_auto_prompt_biometric"
    }
}

object FakeAuthService {
    fun validate(username: String, password: String): Boolean {
        return username.isNotBlank() && password.isNotBlank() && password.length >= 4
    }
}

class HomeActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (!AuthPrefs.isAuthenticated(this)) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
            return
        }

        setContentView(R.layout.activity_home)

        findViewById<View>(R.id.btnLogout)?.setOnClickListener {
            confirmLogout()
        }
    }

    private fun confirmLogout() {
        AlertDialog.Builder(this)
            .setTitle(getString(R.string.logout_title))
            .setMessage(getString(R.string.logout_message))
            .setPositiveButton(getString(R.string.logout)) { _, _ ->
                AuthPrefs.clear(this)
                startActivity(Intent(this, LoginActivity::class.java))
                finish()
            }
            .setNegativeButton(getString(R.string.cancel), null)
            .show()
    }
}